text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표일은 '스모크 테스트 통과 시' 금요일 15:00(KST)로 확정된다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "패키지명 불일치 처리에 대해 smoke-theme-pack.mjs를 무조건 무시하도록 변경하는 제안은 채택되지 않았다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "패키지명 불일치가 발생하면 스크립트를 먼저 수정하기보다 패키지 설정/계약을 먼저 점검하고, 계약 자체가 잘못되었을 때만 스크립트를 검토한다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "Minjun은 금요일 10:00(KST)까지 스모크 테스트를 재실행하고 결과를 공유한다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "Doyun은 금요일 12:00(KST)까지 action_items.md에 실패 트리아지 노트를 작성한다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "Hara는 Minjun의 스모크 결과 게시 후 생성 tarball 경로를 확인한다.",
        "source": "회의록(raw notes)"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara가 제안한 `smoke-theme-pack.mjs` 패키지명 mismatch 무시 처리",
        "decision": "거부",
        "reason": "계약/설정 점검 후 필요할 때만 스크립트 점검이 원칙으로 합의됨",
        "source": "회의록(raw notes)"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 릴리스 목표는 내부 스트레치 목표로 언급됨(확정 릴리스 목표가 아님).",
        "source": "회의록(raw notes)"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 가이드는 가능하면 목요일에 검토 제안되었으나, 담당자/마감시한은 할당되지 않았다.",
        "source": "회의록(raw notes)"
      },
      {
        "item": "Hara의 tarball 경로 점검은 미정된 시점(‘결과 게시 후’)으로 계획됨.",
        "source": "회의록(raw notes)"
      }
    ],
    "risks": [
      {
        "item": "생성 tarball 경로가 잘못되면 릴리스가 지연될 수 있음",
        "source": "회의록(raw notes)",
        "impact": "중간-높음"
      },
      {
        "item": "README 설치 단계가 오래되면 릴리스 노트/안내가 사용자에게 오도될 수 있음",
        "source": "회의록(raw notes)",
        "impact": "중간"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "내부 스트레치 목표인 수요일 일정을 공개 릴리스 노트에 기재할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 게시 후 생성 tarball 경로 확인",
      "due": "미정(결과 게시 이후)",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "미정(목요일 권장)",
      "status": "제안/미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 결과 공유 후, smoke 통과 여부와 tarball 경로 점검 이슈 연계 처리",
      "Doyun의 트리아지 노트 제출 상태 확인(금요일 12:00 KST 기한 기준 추적)",
      "최종 릴리스 승인 권한자 확정 여부 확인 후, 승인 플로우 문서화",
      "README 설치 단계 최신성 검토 필요성 및 담당자 확정",
      "내부 스트레치 목표(수요일)와 공개 릴리스 목표(금요일 15:00 KST)가 문서/공지에서 혼동되도록 표기되지 않도록 점검"
    ],
    "what_not_to_invent": [
      "고객/외부 파트너 이름",
      "예산 관련 수치·한도·승인 내역",
      "보안 사고 또는 장애 사실",
      "법무 승인 요구사항",
      "소유자 미기재 항목의 임의 주인 지정",
      "미확정 마감시한 임의 추정"
    ]
  },
  "non_invention_rules": [
    "제공된 합성 fixture 외의 사실을 추가로 추정하여 채우지 않는다.",
    "고객, 예산, 보안, 장애, 법무, 소유자 미기재 항목, 미정 마감시한은 생성하지 않는다.",
    "회의록에 없는 수치(예: 진행률, 성공률, 일정 지표)는 추가하지 않는다.",
    "오픈 질문에는 임의 정답을 쓰지 않고 추적 과제로 남긴다."
  ]
}
